Here's a complete test class using modern MSTest v3+ patterns:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    // Helper: create a DataFetcher backed by a fake handler
    private static DataFetcher CreateFetcher(
        HttpStatusCode statusCode,
        string content = "")
    {
        var handler = new FakeHandler(statusCode, content);
        var client = new HttpClient(handler);
        return new DataFetcher(client);
    }

    [TestMethod]
    [Timeout(5000)] // guards against hangs — fails the test after 5 s
    public async Task FetchAsync_ReturnsContent_OnSuccess(
        CancellationToken cancellationToken)   // MSTest v3 injects a token
    {                                           // that fires when [Timeout] expires
        var fetcher = CreateFetcher(HttpStatusCode.OK, "hello");

        var result = await fetcher.FetchAsync(
            "https://example.com", cancellationToken);

        Assert.AreEqual("hello", result);
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_Throws_OnServerError(
        CancellationToken cancellationToken)
    {
        var fetcher = CreateFetcher(HttpStatusCode.InternalServerError);

        await Assert.ThrowsExceptionAsync<HttpRequestException>(
            () => fetcher.FetchAsync("https://example.com", cancellationToken));
    }

    [TestMethod]
    public async Task FetchAsync_Throws_WhenAlreadyCancelled()
    {
        var fetcher = CreateFetcher(HttpStatusCode.OK, "data");
        using var cts = new CancellationTokenSource();
        cts.Cancel(); // pre-cancel

        await Assert.ThrowsExceptionAsync<TaskCanceledException>(
            () => fetcher.FetchAsync("https://example.com", cts.Token));
    }

    [TestMethod]
    public async Task FetchAsync_Throws_WhenCancelledDuringRequest()
    {
        // Handler cancels the token mid-flight
        using var cts = new CancellationTokenSource();
        var handler = new CancellingHandler(cts);
        var fetcher = new DataFetcher(new HttpClient(handler));

        await Assert.ThrowsExceptionAsync<TaskCanceledException>(
            () => fetcher.FetchAsync("https://example.com", cts.Token));
    }

    // ── Fakes ───────────────────────────────────────────────

    private sealed class FakeHandler(
        HttpStatusCode statusCode, string content) : HttpMessageHandler
    {
        protected override Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            cancellationToken.ThrowIfCancellationRequested();
            var response = new HttpResponseMessage(statusCode)
            {
                Content = new StringContent(content)
            };
            return Task.FromResult(response);
        }
    }

    private sealed class CancellingHandler(
        CancellationTokenSource cts) : HttpMessageHandler
    {
        protected override Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            cts.Cancel(); // simulate cancellation mid-request
            cancellationToken.ThrowIfCancellationRequested();
            return Task.FromResult(new HttpResponseMessage(HttpStatusCode.OK));
        }
    }
}
```

**Key patterns demonstrated:**

| Pattern | How |
|---|---|
| **Async tests** | Return `Task`, use `async`/`await` — MSTest awaits them natively |
| **Timeout** | `[Timeout(ms)]` attribute fails the test if it hangs |
| **Injected token** | MSTest v3 passes a `CancellationToken` parameter that fires on timeout — wire it through to your SUT |
| **Cancellation** | Test both pre-cancelled and mid-flight cancellation via `CancellationTokenSource` |
| **No mocking library needed** | A custom `HttpMessageHandler` avoids real HTTP and heavy mocking dependencies |

> **Important:** the `CancellationToken` parameter injection requires **MSTest v3.3+** (`Microsoft.Testing.Extensions.MSTest` or `MSTest` ≥ 3.3). On older versions, read `TestContext.CancellationTokenSource.Token` instead.
